import torch
import torch.nn as nn
import torch.nn.functional as F
from torch.utils.cpp_extension import load_inline

cpp_source = r"""
#include <torch/extension.h>

void fused_linear_relu(torch::Tensor input, torch::Tensor weight, torch::Tensor bias, torch::Tensor output) {
    int m = input.size(0);
    int n = input.size(1);
    int k = weight.size(1);

    #pragma omp parallel for collapse(2)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < k; ++j) {
            float sum = 0;
            for (int l = 0; l < n; ++l) {
                sum += input[i * n + l] * weight[j * n + l];
            }
            output[i * k + j] = std::max(sum + bias[j], 0.0f);
        }
    }
}
"""

cuda_source = r"""
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cublas_v2.h>

#define TILE_WIDTH 128

__global__ void gemm_kernel(float* A, float* B, float* C, int m, int n, int k) {
    __shared__ float As[TILE_WIDTH][TILE_WIDTH];
    __shared__ float Bs[TILE_WIDTH][TILE_WIDTH];

    int bx = blockIdx.x, by = blockIdx.y;
    int tx = threadIdx.x, ty = threadIdx.y;
    int Row = by * TILE_WIDTH + ty;
    int Col = bx * TILE_WIDTH + tx;

    float Csub = 0.0f;

    for (int m = 0; m < (k + TILE_WIDTH - 1) / TILE_WIDTH; ++m) {
        if (Row < m * TILE_WIDTH + TILE_WIDTH && Col < k) {
            As[ty][tx] = A[Row * k + Col];
        } else {
            As[ty][tx] = 0.0f;
        }

        if (Col < m * TILE_WIDTH + TILE_WIDTH && Row < m * TILE_WIDTH + TILE_WIDTH) {
            Bs[ty][tx] = B[Col * k + Row];
        } else {
            Bs[ty][tx] = 0.0f;
        }

        __syncthreads();

        for (int kk = 0; kk < TILE_WIDTH; ++kk) {
            Csub += As[ty][kk] * Bs[kk][tx];
        }

        __syncthreads();
    }

    if (Row < m * TILE_WIDTH + TILE_WIDTH && Col < n) {
        C[Row * n + Col] = Csub;
    }
}

void fused_linear_relu_cuda(torch::Tensor input, torch::Tensor weight, torch::Tensor bias, torch::Tensor output) {
    int m = input.size(0);
    int n = input.size(1);
    int k = weight.size(1);

    cublasHandle_t handle;
    cublasCreate(&handle);

    dim3 threads(TILE_WIDTH, TILE_WIDTH);
    dim3 blocks((n + TILE_WIDTH - 1) / TILE_WIDTH, (k + TILE_WIDTH - 1) / TILE_WIDTH);

    gemm_kernel<<<blocks, threads>>>(input.data_ptr<float>(), weight.data_ptr<float>(), output.data_ptr<float>(), m, n, k);

    cublasDestroy(handle);

    #pragma omp parallel for collapse(2)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < k; ++j) {
            output[i * k + j] = std::max(output[i * k + j] + bias[j], 0.0f);
        }
    }
}
"""

