#include <ATen/core/Tensor.h>
#include <torch/script.h>

void fuse_concat_bias_relu_scale_clamp(at::Tensor x, at::Tensor bias, at::Tensor scale, float clamp_val, at::Tensor out) {
    int B = x.size(0);
    int C = x.size(1);
    int H = x.size(2);
    int W = x.size(3);

    for (int b = 0; b < B; ++b) {
        for (int c = 0; c < C; ++c) {
            for (int h = 0; h < H; ++h) {
                for (int w = 0; w < W; ++w) {
                    out[b * C + c][h][w] = std::max(std::min(scale[c] * (x[b * C + c][h][w] + bias[c]), clamp_val), -clamp_val);
                }
            }
        }
    }
}
"""

cuda_sources = """
#include <ATen/core/Tensor.h>
#include <torch/script.h>
#include <cuda_runtime.h>
#include <cmath>

__global__ void fuse_concat_bias_relu_scale_clamp_kernel(const float* x, const float* bias, const float* scale, float clamp_val, float* out, int B, int C, int H, int W) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int b = idx / (C * H * W);
    int c_h_w = idx % (C * H * W);
    int c = c_h_w / (H * W);
    int h_w = c_h_w % (H * W);
    int h = h_w / W;
    int w = h_w % W;

    out[b * C + c][h][w] = std::max(std::min(scale[c] * (x[b * C + c][h][w] + bias[c]), clamp_val), -clamp_val);
}

void fuse_concat_bias_relu_scale_clamp_cuda(torch::Tensor x, torch::Tensor bias, torch::Tensor scale, float clamp_val, torch::Tensor out) {
