#include <torch/extension.h>

void fused_conv_relu(torch::Tensor x, torch::Tensor w, torch::Tensor b, torch::Tensor out) {
    // Simple GEMM + ReLU fusion
    auto x_ptr = x.data_ptr<float>();
    auto w_ptr = w.data_ptr<float>();
    auto b_ptr = b.data_ptr<float>();
    auto out_ptr = out.data_ptr<float>();

    int M = x.size(0);
    int K = x.size(2) * x.size(3);
    int N = w.size(1);

    float* A = new float[M * K];
    float* B = new float[K * N];

    // Flatten x and w
    for (int i = 0; i < M; ++i) {
        for (int k = 0; k < K; ++k) {
            A[i * K + k] = x_ptr[i * K + k];
        }
    }

    for (int k = 0; k < K; ++k) {
        for (int n = 0; n < N; ++n) {
            B[k * N + n] = w_ptr[k * N + n];
        }
    }

    // Perform GEMM
    for (int m = 0; m < M; ++m) {
        for (int n = 0; n < N; ++n) {
            out_ptr[m * N + n] = 0;
            for (int k = 0; k < K; ++k) {
                out_ptr[m * N + n] += A[m * K + k] * B[k * N + n];
            }
            out_ptr[m * N + n] += b_ptr[n];
            if (out_ptr[m * N + n] <= 0) {
                out_ptr[m * N + n] = 0;
            }
        }
    }

    delete[] A;
    delete[] B;
}
"""

