#include <torch/extension.h>
#include <cublas_v2.h>
#include <thrust/device_vector.h>
#include <thrust/reduce.h>

__global__ void fused_conv_relu_kernel(float* x, float* w, float* b, float* out, int M, int K, int N) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= M * N) return;

    float sum = 0;
    for (int k = 0; k < K; ++k) {
        sum += x[idx / N * K + k] * w[k * N + idx % N];
    }
    out[idx] = sum + b[idx % N];
    if (out[idx] <= 0) {
        out[idx] = 0;
    }
}

void fused_conv_relu_cuda(torch::Tensor x, torch::Tensor w, torch::Tensor b, torch::Tensor out) {
    int M = x.size(0);
    int K = x.size(2) * x.size(3);
    int N = w.size(1);

    fused_conv_relu_kernel<<<(M * N + 255) / 256, 256>>>(x.data_ptr<float>(), w.data_ptr<float>(), b.data_ptr<float>(), out.data_ptr<float>(), M, K, N);
    cudaDeviceSynchronize();
}
"""

